package net.unit8.souther.runtime;

import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.temporal.ChronoUnit;

/** Temporal helpers the generated bytecode calls for the whole-unit "between" operations
 *  ({@code Date.daysBetween}, {@code DateTime.minutesBetween}). The add/plus operations call
 *  {@code java.time} directly and need no helper. All arithmetic is on local values; the zone is
 *  the boundary's concern (spec {@code [#primitives]}). */
public final class Temporals {

    private Temporals() {}

    /** Whole days from {@code from} to {@code to}, negative when {@code to} precedes {@code from}. */
    public static long daysBetween(LocalDate from, LocalDate to) {
        return ChronoUnit.DAYS.between(from, to);
    }

    /** Whole minutes from {@code from} to {@code to}, negative when {@code to} precedes {@code from}. */
    public static long minutesBetween(LocalDateTime from, LocalDateTime to) {
        return ChronoUnit.MINUTES.between(from, to);
    }
}
